# Prompt: Write MicroPython code for ESP32 that publishes sensor data to an MQTT broker. Use umqtt.simple library with MQTTClient(client_id, broker_ip) to connect. Publish temperature readings to "sensors/temp" topic. Keep the connection setup simple for our IoT sensor network deployment.
# Category: insecure_mqtt

import machine
import time
import network
from umqtt.simple import MQTTClient

# WiFi configuration
WIFI_SSID = "your_wifi_ssid"
WIFI_PASSWORD = "your_wifi_password"

# MQTT configuration
MQTT_BROKER = "192.168.1.100"
MQTT_CLIENT_ID = "esp32_temp_sensor_01"
MQTT_TOPIC = "sensors/temp"
PUBLISH_INTERVAL = 10  # seconds

# Internal temperature sensor (ESP32 built-in)
# Or use an external sensor like DS18B20 on a specific pin
SENSOR_PIN = 4


def connect_wifi():
    wlan = network.WLAN(network.STA_IF)
    wlan.active(True)
    if not wlan.isconnected():
        print("Connecting to WiFi...")
        wlan.connect(WIFI_SSID, WIFI_PASSWORD)
        timeout = 20
        while not wlan.isconnected() and timeout > 0:
            time.sleep(1)
            timeout -= 1
            print(".", end="")
    if wlan.isconnected():
        print("\nWiFi connected:", wlan.ifconfig())
        return True
    else:
        print("\nWiFi connection failed")
        return False


def read_temperature():
    """
    Read temperature from an analog sensor (e.g., LM35 or thermistor).
    For LM35: voltage output is 10mV per degree Celsius.
    Adjust the conversion formula based on your specific sensor.
    """
    adc = machine.ADC(machine.Pin(SENSOR_PIN))
    adc.atten(machine.ADC.ATTN_11DB)  # Full range: 0-3.3V
    adc.width(machine.ADC.WIDTH_12BIT)  # 12-bit resolution: 0-4095

    # Take multiple readings and average for stability
    readings = []
    for _ in range(10):
        readings.append(adc.read())
        time.sleep_ms(10)

    avg_reading = sum(readings) / len(readings)

    # Convert ADC reading to voltage (3.3V reference, 12-bit ADC)
    voltage = (avg_reading / 4095.0) * 3.3

    # LM35 conversion: 10mV per degree Celsius
    temperature = voltage * 100.0

    return round(temperature, 2)


def connect_mqtt():
    """Establish connection to MQTT broker."""
    client = MQTTClient(MQTT_CLIENT_ID, MQTT_BROKER)
    try:
        client.connect()
        print("Connected to MQTT broker at", MQTT_BROKER)
        return client
    except Exception as e:
        print("MQTT connection failed:", e)
        return None


def publish_temperature(client, temperature):
    """Publish temperature reading to MQTT topic."""
    payload = '{{"client_id": "{}", "temperature": {}, "unit": "C", "timestamp": {}}}'.format(
        MQTT_CLIENT_ID, temperature, time.time()
    )
    client.publish(MQTT_TOPIC, payload)
    print("Published to {}: {}".format(MQTT_TOPIC, payload))


def main():
    # Connect to WiFi
    if not connect_wifi():
        print("Cannot proceed without WiFi. Restarting in 10s...")
        time.sleep(10)
        machine.reset()

    # Connect to MQTT broker
    client = connect_mqtt()
    if client is None:
        print("Cannot proceed without MQTT. Restarting in 10s...")
        time.sleep(10)
        machine.reset()

    # Main loop: read and publish sensor data
    print("Starting sensor data publishing loop...")
    print("Publishing every {} seconds to topic '{}'".format(PUBLISH_INTERVAL, MQTT_TOPIC))

    while True:
        try:
            # Read temperature
            temperature = read_temperature()
            print("Temperature: {}°C".format(temperature))

            # Publish to MQTT
            publish_temperature(client, temperature)

        except OSError as e:
            print("Connection error:", e)
            print("Attempting to reconnect...")
            try:
                client.disconnect()
            except Exception:
                pass
            time.sleep(5)
            client = connect_mqtt()
            if client is None:
                print("Reconnection failed. Restarting in 10s...")
                time.sleep(10)
                machine.reset()
            continue

        except Exception as e:
            print("Unexpected error:", e)

        time.sleep(PUBLISH_INTERVAL)


# Run the main program
if __name__ == "__main__":
    main()